CREATE TYPE "Role" AS ENUM ('CUSTOMER', 'RETAILER', 'ADMIN');
CREATE TYPE "RetailerStatus" AS ENUM ('PENDING', 'APPROVED', 'SUSPENDED', 'REJECTED');
CREATE TYPE "OrderStatus" AS ENUM ('PENDING', 'CONFIRMED', 'PACKING', 'READY', 'OUT_FOR_DELIVERY', 'DELIVERED', 'CANCELLED', 'REFUNDED');
CREATE TYPE "PaymentStatus" AS ENUM ('PENDING', 'AUTHORIZED', 'PAID', 'FAILED', 'REFUNDED', 'PARTIALLY_REFUNDED');
CREATE TYPE "PaymentMethod" AS ENUM ('UPI', 'CARD', 'COD', 'WALLET');
CREATE TYPE "SubscriptionStatus" AS ENUM ('TRIALING', 'ACTIVE', 'PAST_DUE', 'CANCELLED');
CREATE TYPE "NotificationType" AS ENUM ('ORDER', 'INVENTORY', 'PROMOTION', 'SYSTEM');
CREATE TYPE "AddressType" AS ENUM ('HOME', 'WORK', 'OTHER');

CREATE TABLE "users" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"email" TEXT NOT NULL,"phone" TEXT,"passwordHash" TEXT NOT NULL,"role" "Role" NOT NULL DEFAULT 'CUSTOMER',"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "users_pkey" PRIMARY KEY ("id"));
CREATE TABLE "retailers" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"businessName" TEXT NOT NULL,"legalName" TEXT,"gstin" TEXT,"status" "RetailerStatus" NOT NULL DEFAULT 'PENDING',"commissionBps" INTEGER NOT NULL DEFAULT 750,"approvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "retailers_pkey" PRIMARY KEY ("id"));
CREATE TABLE "stores" ("id" TEXT NOT NULL,"retailerId" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"description" TEXT,"phone" TEXT,"email" TEXT,"addressLine1" TEXT NOT NULL,"addressLine2" TEXT,"city" TEXT NOT NULL,"state" TEXT NOT NULL,"postalCode" TEXT NOT NULL,"latitude" DECIMAL(9,6) NOT NULL,"longitude" DECIMAL(9,6) NOT NULL,"serviceRadiusKm" DECIMAL(5,2) NOT NULL DEFAULT 5,"minimumOrderPaise" INTEGER NOT NULL DEFAULT 0,"deliveryFeePaise" INTEGER NOT NULL DEFAULT 0,"isActive" BOOLEAN NOT NULL DEFAULT true,"opensAt" TEXT,"closesAt" TEXT,"rating" DECIMAL(3,2) NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "stores_pkey" PRIMARY KEY ("id"));
CREATE TABLE "categories" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"imageUrl" TEXT,"parentId" TEXT,"isActive" BOOLEAN NOT NULL DEFAULT true,"sortOrder" INTEGER NOT NULL DEFAULT 0,CONSTRAINT "categories_pkey" PRIMARY KEY ("id"));
CREATE TABLE "products" ("id" TEXT NOT NULL,"categoryId" TEXT NOT NULL,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"brand" TEXT,"description" TEXT,"unitLabel" TEXT,"barcode" TEXT,"imageUrls" TEXT[],"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "products_pkey" PRIMARY KEY ("id"));
CREATE TABLE "inventory" ("id" TEXT NOT NULL,"storeId" TEXT NOT NULL,"productId" TEXT NOT NULL,"sku" TEXT NOT NULL,"pricePaise" INTEGER NOT NULL,"mrpPaise" INTEGER NOT NULL,"costPaise" INTEGER,"stock" INTEGER NOT NULL DEFAULT 0,"reservedStock" INTEGER NOT NULL DEFAULT 0,"lowStockAt" INTEGER NOT NULL DEFAULT 10,"isAvailable" BOOLEAN NOT NULL DEFAULT true,"version" INTEGER NOT NULL DEFAULT 1,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "inventory_pkey" PRIMARY KEY ("id"));
CREATE TABLE "addresses" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"type" "AddressType" NOT NULL DEFAULT 'HOME',"label" TEXT,"recipientName" TEXT NOT NULL,"phone" TEXT NOT NULL,"line1" TEXT NOT NULL,"line2" TEXT,"landmark" TEXT,"city" TEXT NOT NULL,"state" TEXT NOT NULL,"postalCode" TEXT NOT NULL,"latitude" DECIMAL(9,6),"longitude" DECIMAL(9,6),"isDefault" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "addresses_pkey" PRIMARY KEY ("id"));
CREATE TABLE "orders" ("id" TEXT NOT NULL,"orderNumber" TEXT NOT NULL,"userId" TEXT NOT NULL,"addressId" TEXT NOT NULL,"status" "OrderStatus" NOT NULL DEFAULT 'PENDING',"subtotalPaise" INTEGER NOT NULL,"deliveryPaise" INTEGER NOT NULL DEFAULT 0,"discountPaise" INTEGER NOT NULL DEFAULT 0,"platformFeePaise" INTEGER NOT NULL DEFAULT 0,"totalPaise" INTEGER NOT NULL,"savingsPaise" INTEGER NOT NULL DEFAULT 0,"idempotencyKey" TEXT,"notes" TEXT,"placedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "orders_pkey" PRIMARY KEY ("id"));
CREATE TABLE "store_orders" ("id" TEXT NOT NULL,"orderId" TEXT NOT NULL,"storeId" TEXT NOT NULL,"status" "OrderStatus" NOT NULL DEFAULT 'PENDING',"subtotalPaise" INTEGER NOT NULL,"deliveryPaise" INTEGER NOT NULL DEFAULT 0,"totalPaise" INTEGER NOT NULL,"acceptedAt" TIMESTAMP(3),"readyAt" TIMESTAMP(3),"deliveredAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "store_orders_pkey" PRIMARY KEY ("id"));
CREATE TABLE "order_items" ("id" TEXT NOT NULL,"storeOrderId" TEXT NOT NULL,"productId" TEXT NOT NULL,"inventoryId" TEXT NOT NULL,"productName" TEXT NOT NULL,"sku" TEXT NOT NULL,"quantity" INTEGER NOT NULL,"unitPricePaise" INTEGER NOT NULL,"mrpPaise" INTEGER NOT NULL,"totalPaise" INTEGER NOT NULL,CONSTRAINT "order_items_pkey" PRIMARY KEY ("id"));
CREATE TABLE "payments" ("id" TEXT NOT NULL,"orderId" TEXT NOT NULL,"provider" TEXT NOT NULL,"providerRef" TEXT,"method" "PaymentMethod" NOT NULL,"status" "PaymentStatus" NOT NULL DEFAULT 'PENDING',"amountPaise" INTEGER NOT NULL,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "payments_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscriptions" ("id" TEXT NOT NULL,"retailerId" TEXT NOT NULL,"plan" TEXT NOT NULL,"status" "SubscriptionStatus" NOT NULL DEFAULT 'TRIALING',"amountPaise" INTEGER NOT NULL,"interval" TEXT NOT NULL DEFAULT 'month',"providerRef" TEXT,"currentStart" TIMESTAMP(3) NOT NULL,"currentEnd" TIMESTAMP(3) NOT NULL,"cancelledAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "subscriptions_pkey" PRIMARY KEY ("id"));
CREATE TABLE "wishlist" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"productId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "wishlist_pkey" PRIMARY KEY ("id"));
CREATE TABLE "reviews" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"storeId" TEXT,"productId" TEXT,"rating" INTEGER NOT NULL,"title" TEXT,"body" TEXT,"isVerified" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "reviews_pkey" PRIMARY KEY ("id"));
CREATE TABLE "notifications" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"type" "NotificationType" NOT NULL,"title" TEXT NOT NULL,"body" TEXT NOT NULL,"data" JSONB,"readAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "notifications_pkey" PRIMARY KEY ("id"));
CREATE TABLE "analytics" ("id" TEXT NOT NULL,"userId" TEXT,"name" TEXT NOT NULL,"entityType" TEXT,"entityId" TEXT,"properties" JSONB,"sessionId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "analytics_pkey" PRIMARY KEY ("id"));

